	Z3_solver_assert(ctx, s, c1);

	c2 = Z3_mk_ge(ctx, a, zero);
	Z3_solver_assert(ctx, s, c2);

	c2 = Z3_mk_ge(ctx, b, zero);
	Z3_solver_assert(ctx, s, c2);

	c2 = Z3_mk_ge(ctx, c, zero);
	Z3_solver_assert(ctx, s, c2);

	iter = 0;
